export function encodeProcessStatusValue(value: ProcessStatus): CborValue {
  switch (value.type) {
    case "idle": {
      const fields = new Map<number, CborValue>();
      return [1, fields];
    }
    case "run": {
      const fields = new Map<number, CborValue>();
      return [2, fields];
    }
    case "sleep": {
      const fields = new Map<number, CborValue>();
      return [3, fields];
    }
    case "stop": {
      const fields = new Map<number, CborValue>();
      return [4, fields];
    }
    case "zombie": {
      const fields = new Map<number, CborValue>();
      return [5, fields];
    }
    case "tracing": {
      const fields = new Map<number, CborValue>();
      return [6, fields];
    }
    case "dead": {
      const fields = new Map<number, CborValue>();
      return [7, fields];
    }
    case "wakekill": {
      const fields = new Map<number, CborValue>();
      return [8, fields];
    }
    case "waking": {
      const fields = new Map<number, CborValue>();
      return [9, fields];
    }
    case "parked": {
      const fields = new Map<number, CborValue>();
      return [10, fields];
    }
    case "lockBlocked": {
      const fields = new Map<number, CborValue>();
      return [11, fields];
    }
    case "uninterruptibleDiskSleep": {
      const fields = new Map<number, CborValue>();
      return [12, fields];
    }
    case "suspended": {
      const fields = new Map<number, CborValue>();
      return [13, fields];
    }
    case "unknown": {
      const fields = new Map<number, CborValue>();
      fields.set(1, u53(required(value.code, "ProcessStatus.Unknown.code")));
      return [14, fields];
    }
  }
}

export function decodeProcessStatusValue(value: CborValue): ProcessStatus {
  const [variantId, fields] = expectUnion(value);
  switch (variantId) {
    case 1:
      return {
        type: "idle",
      };
    case 2:
      return {
        type: "run",
      };
    case 3:
      return {
        type: "sleep",
      };
    case 4:
      return {
        type: "stop",
      };
    case 5:
      return {
        type: "zombie",
      };
    case 6:
      return {
        type: "tracing",
      };
    case 7:
      return {
        type: "dead",
      };
    case 8:
      return {
        type: "wakekill",
      };
    case 9:
      return {
        type: "waking",
      };
    case 10:
      return {
        type: "parked",
      };
    case 11:
      return {
        type: "lockBlocked",
      };
    case 12:
      return {
        type: "uninterruptibleDiskSleep",
      };
    case 13:
      return {
        type: "suspended",
      };
    case 14:
      return {
        type: "unknown",
        code: fieldOrDefault(fields.get(1), (value) => integer(value), () => 0),
      };
  }
  throw new Error(`unknown ProcessStatus variant ${variantId}`);
}

